module multi_pipe_4bit (
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

    parameter size = 4;
    wire [size-1:0] mul_a_ext, mul_b_ext;
    reg [size-1:0] partial_products [size-1:0];
    reg [size:0] sum [size:0];
    integer i;

    assign mul_a_ext = {4'b0, mul_a};
    assign mul_b_ext = {4'b0, mul_b};

    always @(*) begin
        for (i = 0; i < size; i = i + 1) begin
            if (mul_b_ext[i])
                partial_products[i] = mul_a_ext << i;
                partial_products[i] = 'd0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i <= size; i = i + 1) begin
                sum[i] <= 'd0;
            end
        end
        else begin
            sum[0] <= {1'b0, partial_products[0]};
            for (i = 1; i < size; i = i + 1) begin
                sum[i] <= sum[i-1] + {1'b0, partial_products[i]};
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            mul_out <= 'd0;
            mul_out <= sum[size];
    end

endmodule
